INSERT INTO public.photos VALUES (24425, 'Monasterio de Cogullada 1913', 'Imagen capturada en el interior de la iglesia del monasterio de Nuestra Seâ”śâ–’ora de Cogullada edificado entre 1658 y 1663 y ocupado originalmente por la Orden de los capuchinos. De estilo barroco, contaba con claustro y cripta, lugar de enterramiento de los miembros de la Cofradâ”śÂˇa de Nuestra Seâ”śâ–’ora de Cogullada, y carneario de capuchinos. En la fotografâ”śÂˇa, aspecto de la iglesia, con la imagen de la Virgen de Cogullada centrando el retablo del altar mayor, bajo baldaquino. A la izquierda, el antiguo pâ”śâ•‘lpito de madera. Completan la escena un par de monjes de la Orden de San Benito, venidos de Solesmes (Francia), a los que les habâ”śÂˇa sido cedido el monasterio en 1896 en râ”śÂ®gimen de usufructo. Posteriores reformas, impulsadas por la entidad de ahorro local que adquiriâ”śâ”‚ el monasterio en 1940, le han dado a esta iglesia su aspecto actual, incluyendo desde el 22 de febrero de 2014 una imagen en bronce de San Josemarâ”śÂˇa Escrivâ”śĂ­ de Balaguer, realizada en forma de altorrelieve y colocada en una de las capillas laterales.', 1913, 1913, 1913, 'Anos 10', 'ACTUR-REY FERNANDO', 41.68923400, -0.84681600, '0101000020E61000005C5837DE1D19EBBF48A5D8D138D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48355687817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48355687817.webp', 'https://www.flickr.com/photos/zaragozaantigua/48355687817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
