INSERT INTO public.photos VALUES (23088, 'Hotel Hiberus 2007', 'Construcciâ”śâ”‚n del Hotel Hiberus, de Josâ”śÂ® Antonio Martâ”śÂˇnez y Elâ”śÂˇas Torres, junto al recinto de la Expo 2008 de Zaragoza. Fuente: picasaweb.google.com/CHELUYS', 2007, 2007, 2007, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66811600, -0.90800400, '0101000020E6100000D06394675E0EEDBF98F738D384D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19940365516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19940365516.webp', 'https://www.flickr.com/photos/zaragozaantigua/19940365516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
