INSERT INTO public.photos VALUES (23095, 'Torre Bergua c.2000', 'Aspecto de la Torre Bergua en el Meandro de Ranillas de Zaragoza, antes de ser derribada. El proyecto de Parque Metropolitano del Agua Luis Buâ”śâ–’uel (2008) contemplaba su salvaciâ”śâ”‚n como ejemplo de este tipo de arquitectura en la zona, pero la iniciativa no prosperâ”śâ”‚. En su solar se encuentra la Escuela Hâ”śÂˇpica Parque del Agua. En la foto, al fondo a la izquierda, destaca el edificio que se levanta en la Vâ”śÂˇa Hispanidad 152, esquina con la avenida de Navarra.', 2000, 2000, 2000, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67039200, -0.91416300, '0101000020E6100000EDD286C3D240EDBF01C0B167CFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22194127380.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22194127380.webp', 'https://www.flickr.com/photos/zaragozaantigua/22194127380/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23096, 'Torre Castillo c.2000', 'Vista de la Torre Castillo, en el Meandro de Ranillas de Zaragoza. Fue destruida cuando se construyâ”śâ”‚ en la zona el Parque Metropolitano del Agua Luis Buâ”śâ–’uel, en 2008. Se hallaba en las inmediaciones del actual embarcadero del Canal de Aguas Bravas, junto a la Torre del Agua. Fuente: apudepa.blogia.com/2008/071501-apudepa-descubre-escandali...', 2000, 2000, 2000, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67064900, -0.90931300, '0101000020E6100000187C9A931719EDBF2C0C91D3D7D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22371953662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22371953662.webp', 'https://www.flickr.com/photos/zaragozaantigua/22371953662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23109, 'Ranillas 2004', 'Vista aâ”śÂ®rea del meandro de Ranillas del râ”śÂˇo Ebro, donde cuatro aâ”śâ–’os despuâ”śÂ®s se instalarâ”śĂ­ la Expo 2008. En primer tâ”śÂ®rmino, la estaciâ”śâ”‚n ferroviaria Zaragoza-Delicias. Fuente: Agencia EFE.', 2004, 2004, 2004, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66832700, -0.91400000, '0101000020E6100000736891ED7C3FEDBF530438BD8BD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24631905442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24631905442.webp', 'https://www.flickr.com/photos/zaragozaantigua/24631905442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23176, 'Parque del Agua 2009', 'Imagen del Canal de Aguas Bravas del Parque Metropolitano del Agua Luis Buâ”śâ–’uel, una de las estupendas instalaciones lâ”śâ•‘dicas puestas en marcha con motivo de la Exposiciâ”śâ”‚n Internacional â”¬Â˝Agua y desarrollo sostenibleâ”¬â•— de 2008. Sus dimensiones fueron diseâ”śâ–’adas para poder albergar competiciones internacionales e incluso actuar como subsede olâ”śÂˇmpica, y el canal puede ser utilizado tanto por deportistas profesionales como por usuarios ocasionales. Varias empresas se han encargado desde entonces de su explotaciâ”śâ”‚n, que se estimaba de unos 100.000 potenciales usuarios anuales entre practicantes del râ”śĂ­fting, piragâ”śâ•ťismo, hidrospeed, cano-raft, hot-dogĂ”Ă‡ÂŞ tanto en las modalidades de descenso, estilo libre y slalom. En marzo de 2017 estas instalaciones, cuya construcciâ”śâ”‚n costâ”śâ”‚ unos 5 millones de euros, han sido cerradas por abandono de la empresa concesionaria, pues el ejercicio de 2016 se cerrâ”śâ”‚ con el trâ”śĂ­nsito de 2000 personas, y el negocio no parece viable en esas condiciones. En la imagen, a la izquierda, el Puente del Tercer Milenio. De fondo, al otro lado del Ebro, la Estaciâ”śâ”‚n de Zaragoza-Delicias. Fuente visual: foto Isabel Pardo, en www.chebro.es/', 2009, 2009, 2009, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66959500, -0.90928900, '0101000020E6100000F699B33EE518EDBF5648F949B5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34770349561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34770349561.webp', 'https://www.flickr.com/photos/zaragozaantigua/34770349561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24756, 'Zaragoza Oeste 2008', 'Vista aâ”śÂ®rea del Oeste de Zaragoza en 2008. De abajo arriba, la Torre del Agua y el Canal de Aguas Bravas del Parque Metropolitano del Agua Luis Buâ”śâ–’uel; el Palacio de Congresos y el Hotel Hiberus; el Pabellâ”śâ”‚n Puente, el Auditorio de la Plaza de Inspiraciones Acuâ”śĂ­ticas (desaparecido); el Puente del Tercer Milenio: el barrio de La Almozara, el Parking Sur de la Expo; la Estaciâ”śâ”‚n Delicias y el barrio de Las Delicias. Fuente: Atlas de la ciudad. Zaragoza, 2009.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66811600, -0.90800400, '0101000020E6100000D06394675E0EEDBF98F738D384D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19431730943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19431730943.webp', 'https://www.flickr.com/photos/zaragozaantigua/19431730943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24758, 'Parque Luis Buâ”śâ–’uel 2008', 'Vista desde la Torre del Agua del Canal de Aguas Bravas del Parque Metropolitano del Agua Luis Buâ”śâ–’uel de Zaragoza, unos meses antes de la inauguraciâ”śâ”‚n de la Expo 2008. El parque fue diseâ”śâ–’ado por Margarita Jover, Iâ”śâ–’aki Alday y Christine Dalnoki. Fuente: picasaweb.google.com/CHELUYS', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66915800, -0.91012900, '0101000020E6100000948444DAC61FEDBFABED26F8A6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19779353900.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19779353900.webp', 'https://www.flickr.com/photos/zaragozaantigua/19779353900/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24761, 'Alma del Ebro 2008', 'El escultor Jaume Plensa instalâ”śâ”‚ una de sus esculturas de personajes formados por letras en el recinto de la Expo 2008 de Zaragoza. La hizo llamar Alma del Ebro y aquâ”śÂˇ la vemos reciâ”śÂ®n colocada y aâ”śâ•‘n protegida por andamios, frente a la entrada del palacio de Congresos. Fuente: picasaweb.google.com/CHELUYS', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66885400, -0.90596600, '0101000020E6100000C636A968ACFDECBF3FE603029DD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19967452225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19967452225.webp', 'https://www.flickr.com/photos/zaragozaantigua/19967452225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24791, 'Torre Montaâ”śâ–’â”śÂ®s 1965', 'La Torre Montaâ”śâ–’â”śÂ®s era una de las construcciones de carâ”śĂ­cter rural en la huerta de Ranillas. Fue derribada, junto con el resto, en 2007, para construir allâ”śÂˇ el parque del Agua Luis Buâ”śâ–’uel, en el marco de la Expo 2008. Fuente: Colecciâ”śâ”‚n particular.', 1965, 1965, 1965, 'Anos 60', 'ACTUR-REY FERNANDO', 41.66903900, -0.91531500, '0101000020E61000004339D1AE424AEDBFD05FE811A3D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32247935084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32247935084.webp', 'https://www.flickr.com/photos/zaragozaantigua/32247935084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24800, 'Mario Vargas Llosa 2008', 'Foto: J. C. Leâ”śâ”‚n. Visita a la Expo 2008, el 19 de agosto, del escritor peruano Mario Vargas Llosa, Premio Nobel de Literatura 2010. Al fondo, la escultura de Jaume Plensa El alma del Ebro. Fuente: Heraldo de Aragâ”śâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66898100, -0.90573000, '0101000020E6100000CF31207BBDFBECBF9C525E2BA1D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32941029443.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32941029443.webp', 'https://www.flickr.com/photos/zaragozaantigua/32941029443/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25983, 'Expo 2008. 2006', 'Vicente Modesto Locual. Febrero 2006 Imagen aâ”śÂ®rea del estado de las obras de la Expo 2008 en el meandro de Ranillas, en sus primeros estadios: la prolongaciâ”śâ”‚n de la calle Pablo Ruiz Picasso, y el seâ”śâ–’alamiento del perâ”śÂˇmetro del espacio de la Expo, y de los futuros puentes del Tercer Milenio y el Pabellâ”śâ”‚n-Puente. La productiva huerta de Ranillas mengua conforme la obra avanza.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66919300, -0.90814300, '0101000020E610000029ECA2E8810FEDBF27DBC01DA8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15332296306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15332296306.webp', 'https://www.flickr.com/photos/zaragozaantigua/15332296306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25988, 'Meandro de Ranillas 2007', 'Imagen de la evoluciâ”śâ”‚n del meandro de Ranillas con motivo de las obras previas a la Expo 2008: Parque del Agua "Luis Buâ”śâ–’uel" (perfecto homenaje absurdo al maestro), recinto ferial, y los puentes asociados al proyecto. Fuente: EXPOAGUA.', 2007, 2007, 2007, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66832700, -0.91400000, '0101000020E6100000736891ED7C3FEDBF530438BD8BD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16488559618.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16488559618.webp', 'https://www.flickr.com/photos/zaragozaantigua/16488559618/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26033, 'Ronda del Rabal 2006', 'Vista parcial del Meandro de Ranillas en febrero de 2006, con la avenida de Ranillas abajo, y la Ronda del Rabal en construcciâ”śâ”‚n. Este vial, que forma parte del Tercer Cinturâ”śâ”‚n de Ronda de la ciudad, arrancaba de la rotonda de intersecciâ”śâ”‚n de la calle Pablo Ruiz Picasso con la avenida de Ranillas y llegaba hasta la avenida Pablo Gargallo, atravesando el râ”śÂˇo Ebro por el puente del Tercer Milenio. Fue construido entre 2005 y 2006, y puesto en uso en 2007. Su nombre desapareciâ”śâ”‚ despuâ”śÂ®s del callejero, pasando a considerarse un nuevo tramo de la calle Picasso. El solar de la derecha, ya explanado para ubicar ahâ”śÂˇ la Expo 2008. El puente del Tercer Milenio, al fondo, en construcciâ”śâ”‚n. Las huertas de arriba, a punto de desaparecer. Fuente: Heraldo de Aragâ”śâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66984400, -0.90328600, '0101000020E6100000B4E89D0AB8E7ECBFFEB5BC72BDD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31087505643.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31087505643.webp', 'https://www.flickr.com/photos/zaragozaantigua/31087505643/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26041, 'Meandro de Ranillas 2006', 'Ortofoto obtenida el 1 de agosto de 2006. Muestra los terrenos abrazados por el meandro de Ranillas, durante la construcciâ”śâ”‚n de la Expo 2008 y sus obras de acompaâ”śâ–’amiento. Fuente: Gobierno de Aragâ”śâ”‚n. Departamento de Presidencia y Relaciones Institucionales. Centro de Documentaciâ”śâ”‚n e Informaciâ”śâ”‚n Territorial de Aragâ”śâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66898800, -0.91230200, '0101000020E61000009C69C2F69331EDBF4EB51666A1D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31257263634.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31257263634.webp', 'https://www.flickr.com/photos/zaragozaantigua/31257263634/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26056, 'Meandro de Ranillas 2006', 'Aâ”śÂ®rea visual del meandro de Ranillas ya impactado por las obras de urbanizaciâ”śâ”‚n previas a la Expo 2008 (avenida de Ranillas, Ronda del Rabal, y puente del Tercer Milenio). La zona que ocuparâ”śĂ­ la Expo 2008 ya se encuentra explanada, y en ejecuciâ”śâ”‚n. La antigua zona de huerta de primer plano serâ”śĂ­ pronto sustituida por unos diversos y singulares espacios de acompaâ”śâ–’amiento que incluyen huertas posmodernas. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 2006, 2006, 2006, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66832700, -0.91400000, '0101000020E6100000736891ED7C3FEDBF530438BD8BD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32998995143.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32998995143.webp', 'https://www.flickr.com/photos/zaragozaantigua/32998995143/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21133, 'Vista 1889', 'Como si de las dos caras de Jano, esta vista de Zaragoza se complementa con la subida hace un par de dâ”śÂˇas, porque confronta con ella. De esta forma, posiblemente habrâ”śÂˇa sido capturada desde la altura de la fâ”śĂ­brica de harinas de Almech, sobre una terraza natural esquinera entre el final de los caminos de Torrero y de las Torres, y el principio de Cuâ”śÂ®llar, permitiendo por ello una insâ”śâ”‚lita vista panorâ”śĂ­mica de la ciudad desde el sur En primer tâ”śÂ®rmino destacan las instalaciones de la Fâ”śĂ­brica de sombreros al por mayor de Felipe Conesa sita en el 293 de la Subida de Cuâ”śÂ®llar, donde el camino de las Alcachoferas angula con el camino de las Torres. A finales de agosto de 1889 esta fâ”śĂ­brica fue asolada por un incendio, tras lo que fue reubicada donde "las cuatro esquinas", en el camino de Montemolâ”śÂˇn a Torrero o camino de San Josâ”śÂ®. donde este empresario fue asesinado de forma truculenta el 30 de diciembre de 1890, tras lo que se convirtiâ”śâ”‚ en un mediâ”śĂ­tico y popular evento muy seguido desde su comisiâ”śâ”‚n y hasta la concesiâ”śâ”‚n de indulto a los reos de muerte casi un aâ”śâ–’o despuâ”śÂ®s: su mujer, su amante, y su asesino. Hemingway incluso sugiriâ”śâ”‚ mâ”śĂ­s tarde que este caso habrâ”śÂˇa servido de referente a la novela "La piedra angular" de Emilia Pardo Bazâ”śĂ­n. La despejada zona central de torres y almacenes dispersos estarâ”śÂˇa delimitada entre el camino de Torrero, a la izquierda, el reciente paseo de las Damas, a la derecha, y el camino de las Torres. La gran estructura del colegio del Sagrado Corazâ”śâ”‚n, y la mâ”śĂ­s grande aâ”śâ•‘n del colegio del Salvador, justo detrâ”śĂ­s, seâ”śâ–’alan el comienzo de la ciudad consolidada. A su izquierda, la torre de San Pablo Apâ”śâ”‚stol y la câ”śâ•‘pula y gran nave central del antiguo convento de San Ildefonso. A su derecha emerge la desmochada Torre Nueva de su triple chapitel. A continuaciâ”śâ”‚n, la torre de la iglesia de Santa Engracia, el templo del Pilar con la inacabada torre de Santiago. Mâ”śĂ­s hacia la derecha, la torre de San Gil Abad, la de San Juan y San Pedro, y cierra el panorama la to', 1889, 1889, 1889, 'Siglo XIX', 'UNIVERSIDAD', 41.64123200, -0.88551500, '0101000020E610000012C2A38D2356ECBF0893E2E313D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49016943013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49016943013.webp', 'https://www.flickr.com/photos/zaragozaantigua/49016943013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21148, 'Litografâ”śÂˇa Portabella 1898', '"Litografâ”śÂˇa Portabella" fue construida segâ”śâ•‘n diseâ”śâ–’o de Fâ”śÂ®lix Navarro Pâ”śÂ®rez en 1897 en el camino de Torrero nâ”¬â•‘ 30. El taller de la imagen, primero en procesar los fotolitos preparados en Zaragoza por Ramâ”śâ”‚n y Cajal, era uno de los mejores ejemplos de arquitectura industrial de la Zaragoza del momento, en estilo eclecticista fin de siglo. En la imagen, el lado largo de la fachada da al paseo de Sagasta, y el corto, al paseo de Ruiseâ”śâ–’ores. El tranvâ”śÂˇa de propulsiâ”śâ”‚n a sangre estâ”śĂ­ subiendo a la playa de Torrero. El negocio se mantuvo, primero como litografâ”śÂˇa, luego como cartonaje, hasta la dâ”śÂ®cada prodigiosa de los aâ”śâ–’os 60.', 1898, 1898, 1898, 'Siglo XIX', 'UNIVERSIDAD', 41.63899700, -0.88636900, '0101000020E6100000EE056685225DECBFFE9E58A7CAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15330292408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15330292408.webp', 'https://www.flickr.com/photos/zaragozaantigua/15330292408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21165, 'Torre Buil 1898', '"Lejâ”śÂˇsimos" de Zaragoza, imagen de 1898 de la torre de Buil, elegante, airosa y amplia finca de recreo sobre parte de la mâ”śĂ­s antigua Torre de Blancas y luego de Jâ”śâ•‘dez, donde la selecta "crâ”śÂżme" de la "gente guapa" de la ciudad festejaba y tomaba aires mâ”śĂ­s puros que los de abajo, pues estaba ubicada sobre una de las elevadas terrazas naturales que caracterizan la zona. Su propietario, Pablo Buil, se opuso con fervor a ser desalojado para que el ayuntamiento realizara, en ese lugar, un pequeâ”śâ–’o parque "raquâ”śÂˇtico y mezquino". Aâ”śâ–’os despuâ”śÂ®s, tras la explanaciâ”śâ”‚n de la zona, comenzarâ”śÂˇa la historia del parque de Pignatelli de Zaragoza, vinculado con el proyecto mâ”śĂ­s global de ensanche burguâ”śÂ®s hacia el sur. En octubre de 1904 serâ”śÂˇa reinstalada la estatua de Pignatelli, referencial elemento, desde entonces, de este peculiar y escaleno parque. Fuente visual: recopilaciâ”śâ”‚n de reportajes "â”¬Ă­Aqui... Zaragoza! ", Josâ”śÂ® Blasco Ijazo.', 1898, 1898, 1898, 'Siglo XIX', 'UNIVERSIDAD', 41.63726900, -0.88515200, '0101000020E6100000D3A57F492A53ECBF98E0D40792D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21181953212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21181953212.webp', 'https://www.flickr.com/photos/zaragozaantigua/21181953212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21297, 'P.â”¬â•‘ de Sagasta 1908', 'Vista del andador central del paseo de Sagasta en 1908, con el tranvâ”śÂˇa circulando entre los frondosos â”śĂ­rboles. A la derecha, edificios que dan entrada a la calle de La Paz. Fuente visual: Colecciâ”śâ”‚n particular.', 1908, 1908, 1908, 'Anos 1900', 'UNIVERSIDAD', 41.64264800, -0.88616100, '0101000020E610000074B33F506E5BECBF7F6B274A42D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32193721206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32193721206.webp', 'https://www.flickr.com/photos/zaragozaantigua/32193721206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23399, 'Valdegurriana 2008', 'Vista aâ”śÂ®rea centrada en las esclusas y parque de Valdegurriana reciâ”śÂ®n concluida la intervenciâ”śâ”‚n comprendida en la unidad U 29 de las obras de acompaâ”śâ–’amiento Expo 2008 para habilitar aquâ”śÂˇ un â”śĂ­rea recreativa y de descanso en el corredor verde del Canal Imperial de Aragâ”śâ”‚n. A la derecha y aguas arriba, la urbanizaciâ”śâ”‚n Pinarcanal. Al fondo y de izquierda a derecha, Puerto Venecia, el nuevo barrio de Valdespartera, el cementerio municipal, el barrio de Casablanca y el distrito Universidad.', 2008, 2008, 2008, 'Siglo XXI', NULL, 41.61116500, -0.85628000, '0101000020E610000011018750A566EBBFDCBA9BA73ACE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54210136734.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54210136734.webp', 'https://www.flickr.com/photos/zaragozaantigua/54210136734/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21408, 'Caballitos zaragozanos 1913', 'Son apenas unos pocos metros de distancia los que separan este apacible lugar del endomingado paseo de Sagasta. En un rinconcillo de "Villa Florida", desocupados y expectantes, y coloristas versiâ”śâ”‚n autocromo, estos caballitos de cartâ”śâ”‚n-piedra fueron fotografiados en 1913 cuando estaban soâ”śâ–’ando con peques. Onâ”śÂˇricos infantes que luego tomarâ”śÂˇan la forma de â”śĂĽgueda, Teresa, Pepito, Federico, Pilar, y Concha. Mientras la espera, y sin pestaâ”śâ–’ear, sus grandes ojos no perdâ”śÂˇan detalle, escrutando el panorama, aunque sâ”śâ”‚lo brillarâ”śÂˇan y destilarâ”śÂˇan vida cuando el sueâ”śâ–’o se esfumara, y sâ”śâ•‘bitamente comenzara el zarandeo y el jineteo, entre una turbamulta de travesuras, sonoras emociones y correveidiles infinitos. Tres coloristas y dispares caballerâ”śÂˇas, tres, a la espera de la irrupciâ”śâ”‚n de la chiquillerâ”śÂˇa de los Chicoy, y los de Castro. Llegarâ”śÂˇan, seguro, mâ”śĂ­s pronto, que tarde. Ellos lo saben, y lo esperan. Son estos caballitos zaragozanos un resorte que nos trae, algo mâ”śĂ­s de un siglo despuâ”śÂ®s, una emocional imagen de otra ciudad interior, que fue esta misma, aunque no lo pareciera. Inmediata al ensanche alto-burguâ”śÂ®s hacia el montaraz sur, esta privilegiada zona, tanto la interior, como la exterior, mutâ”śâ”‚ luego a otra cosa, a otra realidad. Asâ”śÂˇ, de la perdida calle del Mediodâ”śÂˇa apenas perduran contados fogonazos del pasado. Como este. Fuente visual: foto de Juan Chicoy Arreceigor (Stereoscopic Autochrome Lumiâ”śÂżre glass plate) www.flickr.com/photos/ricardosanzcortiella/12388790783/in...', 1913, 1913, 1913, 'Anos 10', 'UNIVERSIDAD', 41.64348800, -0.88669400, '0101000020E6100000CDE67118CC5FECBF29AF95D05DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26741774722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26741774722.webp', 'https://www.flickr.com/photos/zaragozaantigua/26741774722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21409, 'Gil de Jasa 1913', 'Autocroma, tranquila y luminosa imagen con el posado de â”śĂĽgueda de Castro Chicoy, en los jardines del entorno de "Villa Florida". Al fondo, acristaladas traseras edilicias del paseo de Sagasta, recayentes a la calle Gil de Jasa, posiblemente, del modernista hotelito de Pedro Marcolaâ”śÂˇn, una muestra, a su pesar, de arquitectura efâ”śÂˇmera zaragozana, como casi todo lo que habâ”śÂˇa por esta zona. La pelota, una singular maravilla multicolor casualmente invitada a la foto, intenta comerse la escena, y casi que lo consigue. Fuente visual: foto de Juan Chicoy Arreceigor (Stereoscopic Autochrome Lumiâ”śÂżre glass plate) www.flickr.com/photos/ricardosanzcortiella/12388617045/in...', 1913, 1913, 1913, 'Anos 10', 'UNIVERSIDAD', 41.64348800, -0.88669400, '0101000020E6100000CDE67118CC5FECBF29AF95D05DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26747661151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26747661151.webp', 'https://www.flickr.com/photos/zaragozaantigua/26747661151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21410, 'Gil de Jasa 1913', 'Imagen con el posado de Concha Chicoy Arreceigor y Federico de Castro Delgado, en los jardines que envolvâ”śÂˇan "Villa Florida". Al fondo, acristaladas traseras recayentes a la calle Gil de Jasa del robusto y clasicista hotelito de Nicolâ”śĂ­s Escoriaza, esquinero entre la calle Cervantes y el paseo de Sagasta. Fuente visual: foto de Juan Chicoy Arreceigor (Stereoscopic Autochrome Lumiâ”śÂżre glass plate) www.flickr.com/photos/ricardosanzcortiella/12388782753/in...', 1913, 1913, 1913, 'Anos 10', 'UNIVERSIDAD', 41.64348800, -0.88669400, '0101000020E6100000CDE67118CC5FECBF29AF95D05DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26813241965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26813241965.webp', 'https://www.flickr.com/photos/zaragozaantigua/26813241965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21413, 'Gil de Jasa 1913', 'Imagen capturada en los jardines perimetrales que envolvâ”śÂˇan la desaparecida Villa Florida (a espaldas del fotâ”śâ”‚grafo) con un grupal y entraâ”śâ–’able posado de Teresa, Pepe, Charo, Rafael y Pilar, hijos de Teresa Dabâ”śĂ­n Vallejo y Rafael Chicoy Arreceigor. Al fondo, la calle Gil de Jasa y las monumentales traseras edilicias del paseo de Sagasta en el tramo entre la calle de Cervantes y la calle del Mediodâ”śÂˇa. Destacaban, a la izquierda, la mâ”śĂ­s clasicista, cuadrangular y robusta casa de Nicolâ”śĂ­s Escoriaza, mientras que la de Pedro Marcolaâ”śÂˇn, de aires mâ”śĂ­s modernistas, quedaba a su vera. En todas ellas sobresalâ”śÂˇan luminosas sus extensas balconadas acristaladas orientadas al oeste, de elaborada tracerâ”śÂˇa, sus jardines y zonas verdes.', 1913, 1913, 1913, 'Anos 10', 'UNIVERSIDAD', 41.64348800, -0.88669400, '0101000020E6100000CDE67118CC5FECBF29AF95D05DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28355877799.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28355877799.webp', 'https://www.flickr.com/photos/zaragozaantigua/28355877799/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21415, 'P.â”¬â•‘ de Ruiseâ”śâ–’ores 1915', 'Dibujo de la fachada principal de "Villa Laura", o casa de Fernando Taberner proyectada en eclâ”śÂ®cticas y sinuosas formas por el arquitecto Miguel â”śĂĽngel Navarro en una propiedad del exclusivo paseo de Ruiseâ”śâ–’ores delimitada por este paseo, la calle del Porvenir, el cauce al aire de la acequia de las Adulas y la lindera finca de Victoriano Zorraquino. La introducciâ”śâ”‚n por el Ayuntamiento en 1913 de la obligatoriedad de presentar proyectos y planos constructivos de las nuevas edificaciones en la ciudad nos permite al menos (y hasta que aparezca algâ”śâ•‘n testimonio fotogrâ”śĂ­fico, ojalâ”śĂ­) siquiera una visual de lo que fuera el proyecto de este singular hotelito de dos alturas, construido junto al cauce de la acequia de las Adulas o de San Josâ”śÂ®, y con una amplia zona de jardines escalonados, fuente, dos bancos y una pequeâ”śâ–’a construcciâ”śâ”‚n auxiliar. Dâ”śÂ®cadas mâ”śĂ­s tarde la casa serâ”śÂˇa derribada y sobre su solar se construirâ”śÂˇan dos edificios de vivienda independientes y bien distintos, uno a finales de los aâ”śâ–’os sesenta, esquinero y con ingreso principal por la calle del Doctor Alcay, y otro ya entrado el siglo XXI, esquinero entre el paseo de Ruiseâ”śâ–’ores y la calle del Porvenir. Fuente visual: "Zaragoza. Arquitectura. Siglo XX", Jesâ”śâ•‘s Martâ”śÂˇnez Verâ”śâ”‚n.', 1915, 1915, 1915, 'Anos 10', 'UNIVERSIDAD', 41.63813100, -0.88758400, '0101000020E6100000DD7D8E8F1667ECBF2AC8CF46AED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30290658887.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30290658887.webp', 'https://www.flickr.com/photos/zaragozaantigua/30290658887/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21453, 'Villa Florida 1915', 'Las hermanas â”śĂĽgueda y Concha de Castro Chicoy posan junto a un cachorro de Mastâ”śÂˇn del Pirineo en esta tierna e inâ”śÂ®dita imagen capturada en el exterior de Villa Florida, hotelito esquinero entre la avenida Central y la calle de Gil de Jasa.', 1915, 1915, 1915, 'Anos 10', 'UNIVERSIDAD', 41.64354200, -0.88692000, '0101000020E6100000E162450DA661ECBF1CCD91955FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51749001055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51749001055.webp', 'https://www.flickr.com/photos/zaragozaantigua/51749001055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21454, 'Villa Florida 1913', 'Cuatro nietos de Josâ”śÂ® Chicoy Ferrer, general Auditor de guerra e Inspector mâ”śÂ®dico de primera clase de sanidad militar, contemplan absortos la cajita de mâ”śâ•‘sica en acciâ”śâ”‚n que sostiene impasible una "tata" en el exterior del "hotelito" denominado "Villa Florida" y situado entre la avenida Central y la calle de Gil de Jasa.', 1913, 1913, 1913, 'Anos 10', 'UNIVERSIDAD', 41.64351000, -0.88689900, '0101000020E6100000035DFB027A61ECBF115322895ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51750902750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51750902750.webp', 'https://www.flickr.com/photos/zaragozaantigua/51750902750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23403, 'Monasterio de Santa Fe de Huerva 1913', 'Iglesia y restos de los claustros en el interior del recinto amurallado del monasterio de Santa Fe de Huerva, en Zaragoza capital, aunque entre Cuarte y Cadrete. Conjunto del siglo XVIII abandonado en 1835. Aâ”śâ•‘n precariamente en pie. Fuente: Delimitaciâ”śâ”‚n comarcal de Zaragoza. Gobierno de Aragâ”śâ”‚n, 2011', 1913, 1913, 1913, 'Anos 10', NULL, 41.57758700, -0.94988800, '0101000020E6100000739CDB847B65EEBF21CCED5EEEC94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18615414668.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18615414668.webp', 'https://www.flickr.com/photos/zaragozaantigua/18615414668/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21455, 'Villa Florida 1914', 'Posado de nueve primos endomingados y escalonados por edad, flanqueados por las dos pequeâ”śâ–’as en brazos de sus "tatas", en el exterior del "hotelito" denominado "Villa Florida" y situado entre la avenida Central y la calle de Gil de Jasa. Mientras las mâ”śĂ­s peques ignoran al fotâ”śâ”‚grafo y seguramente miran a sus madres, los demâ”śĂ­s muestran una interesante galerâ”śÂˇa de actitudes ante el objetivo.', 1914, 1914, 1914, 'Anos 10', 'UNIVERSIDAD', 41.64349300, -0.88688800, '0101000020E610000009E066F16261ECBF3B1A87FA5DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51765752784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51765752784.webp', 'https://www.flickr.com/photos/zaragozaantigua/51765752784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21575, 'P.â”¬â•‘ de Sagasta 1929', 'Imagen de la reciente y caracterâ”śÂˇstica "Casa Faci", diseâ”śâ–’ada por Regino Borobio Ojeda para el nâ”¬â•‘ 39 (antiguo) del paseo de Sagasta, chaflanera con el camino de las Torres, cuando sus bajos comerciales estaban ocupados por el "Garage Ferrer", y el concesionario de vehâ”śÂˇculos "Studebaker-Peugeot". Un sencillo surtidor de gasolina, justo en la esquina. A su izquierda, un pedacito del antiguo nâ”¬â•‘ 37 del paseo, edificio de viviendas proyectado por Manuel Martâ”śÂˇnez de Ubago para el Conde de Montenegrâ”śâ”‚n, inicialmente de cinco plantas, que en 1950 serâ”śĂ­ ampliado tres plantas mas, y un sobreâ”śĂ­tico. Al menos, sobreviviâ”śâ”‚, que "Casa Faci", no. A la derecha, al otro lado del Camino de las Torres, y tras la canalina acequia de las Adulas, o de San Josâ”śÂ®, talleres de la enorme Fâ”śĂ­brica de Acumuladores Tudor S.A. "La Pilar". Fuente visual: Foto "La Ampliadora Moderna", en "Regino y Josâ”śÂ® Borobio: arquitectura y fotografâ”śÂˇa. Zaragoza, 1923-1969", Iâ”śâ–’aki Bergera y Daniel Estabâ”śÂ®n, IFC, 2015.', 1929, 1929, 1929, 'Anos 20', 'UNIVERSIDAD', 41.64011800, -0.88620700, '0101000020E61000008A8F4FC8CE5BECBF5CCAF962EFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24262679719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24262679719.webp', 'https://www.flickr.com/photos/zaragozaantigua/24262679719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21622, 'P.â”¬â•‘ de Sagasta 1929', 'Imagen capturada, posiblemente, desde las alturas de la modernista Casa Palao, en la avenida del Siglo XX, con una buena visual del aspecto del paseo de Sagasta en su tramo inmediato al arranque del camino de las Torres, tanto a un lado, como al otro. Fuente visual: www.ebay.es/', 1929, 1929, 1929, 'Anos 20', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33466092996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33466092996.webp', 'https://www.flickr.com/photos/zaragozaantigua/33466092996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21625, 'P.â”¬â•‘ de Sagasta 1927', 'El zaragozano Lorenzo Gradâ”śÂ® posa junto a su prototipo de automâ”śâ”‚vil, aparcado frente al concesionario de las marcas de vehâ”śÂˇculos Oakland y Chevrolet (ambas de General Motors), regentado por Josâ”śÂ® Marâ”śÂˇa Orobitg en el 35 del paseo de Sagasta (hoy 43, albergando una farmacia). Fuente: Colecciâ”śâ”‚n particular.', 1927, 1927, 1927, 'Anos 20', 'UNIVERSIDAD', 41.64059300, -0.88618900, '0101000020E6100000F165A208A95BECBFF58590F3FED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35856209283.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35856209283.webp', 'https://www.flickr.com/photos/zaragozaantigua/35856209283/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21646, 'Pâ”¬â•‘. de Sagasta 1926', 'Inâ”śÂ®dita imagen centrada en la pescaderâ”śÂˇa "La Donostiarra" establecida en el destacado inmueble del nâ”¬â•‘ 21 del paseo de Sagasta, esquinero con la calle de la Paz (a la izquierda) y cuyo aspecto definitivo era resultado de la ampliaciâ”śâ”‚n y reforma proyectadas por el arquitecto Manuel Martâ”śÂˇnez Ubago en 1917. En la imagen, el propietario del negocio y el infante aprendiz posan con las cestas utilizadas para el reparto a domicilio del gâ”śÂ®nero (pescado fresco y salado, marisco, conservas y escabeches) en los selectas viviendas de este "elegante barrio".', 1926, 1926, 1926, 'Anos 20', 'UNIVERSIDAD', 41.64266000, -0.88599800, '0101000020E6100000F9484A7A185AECBF4339D1AE42D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51278996595.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51278996595.webp', 'https://www.flickr.com/photos/zaragozaantigua/51278996595/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21655, 'Paseo de Sagasta c.1923', 'Maravillosa e inâ”śÂ®dita imagen del paseo de Sagasta capturada desde la casa de Abizanda, ubicada entre la de Carlos Palao y la litografâ”śÂˇa de la Viuda de Portabella. La destacada altura del edificio nos ofrece una perspectiva muy interesante del tramo del paseo desde la trinchera del ferrocarril de Madrid a Barcelona, al fondo, y hasta la zona donde el paseo levemente curvea en su encuentro, en primer tâ”śÂ®rmino, con el final del camino de las Torres, ademâ”śĂ­s de con el camino del Sâ”śĂ­bado y la calle de Anselmo Gascâ”śâ”‚n de Gotor. La vista nos ofrece el panorama edilicio de este tramo del paseo, tanto en el lado de los pares, donde a la izquierda destaca aislada "Villa Dolores" o casa del Doctor Arpal (cuyos balcones aparecen engalanados posiblemente siguiendo las instrucciones del Bando municipal dado en diciembre de 1923 ante la visita a Zaragoza de los Reyes de Espaâ”śâ–’a), y un poco antes la notable casa de Emerenciano Garcâ”śÂˇa, sobre la que despunta la chimenea de la fâ”śĂ­brica de hierro esmaltado de Manuel Viâ”śâ–’ado ubicada mâ”śĂ­s abajo, entre la trinchera del ferrocarril y el camino de la Cadena. Hacia el fondo, sobre el paseo emerge poderosa la câ”śâ•‘pula de la iglesia parroquial de Santiago. En el centro de la escena, el andador central del paseo se nos muestra muy despejado tras la tala de sus antiguos â”śĂ­rboles, sustituidos por unos nuevos que en la imagen lucen todavâ”śÂˇa muy poco. A la derecha y en primer tâ”śÂ®rmino, murete inmediato a la fâ”śĂ­brica del acumulador Tudor tras el que fluâ”śÂˇa al aire la acequia de san Josâ”śÂ® en su descenso hacia el camino de las Torres. Tras este camino, despejado aspecto del tramo edilicio del paseo de los impares desde la coqueta y afrancesada casa de Alberto Carriâ”śâ”‚n Garmendia, director gerente del Banco de Aragâ”śâ”‚n, y hasta la alabeada esquina o chaflâ”śĂ­n con el camino de las Torres, un tramo en donde poco despuâ”śÂ®s se construirâ”śÂˇan hasta cuatro notables muestras de la arquitectura de mediados de los aâ”śâ–’os veinte: dos para Mariano Baselga Jordâ”śĂ­n (la primera ya en obras), ot', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.64003000, -0.88644800, '0101000020E6100000F3583332C85DECBFBD3AC780ECD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52227299323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52227299323.webp', 'https://www.flickr.com/photos/zaragozaantigua/52227299323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21724, 'Av. de la Repâ”śâ•‘blica c.1927', 'Imagen editada como postal por la editorial Heliotipia Artâ”śÂˇstica Espaâ”śâ–’ola, capturada en el tramo final de de la avenida hasta el arranque del camino de las Torres inmediato, hacia la derecha, donde destaca la monumental Casa Faci y su alabeada esquina. Justo al otro lado de la avenida, las tres viviendas unifamiliares que originalmente llevaron la llamativa numeraciâ”śâ”‚n de 26 Triplicado, Cuadruplicado y Quintuplicado. El solar hasta el nâ”¬â•‘ 26 Duplicado serâ”śÂˇa edificado pocos aâ”śâ–’os despuâ”śÂ®s con la moderna casa de J. Sâ”śĂ­nchez Ventura. Al fondo destaca el nâ”¬â•‘ 26 o casa de Emerenciano Garcâ”śÂˇa. Ninguna de las referidas viviendas perdura. En primer tâ”śÂ®rmino, una unidad tranviaria posiblemente de la serie 50 en la lâ”śÂˇnea 5 o de Torrero transita junto al pasavâ”śÂˇas utilizado por el servicio corto que llegaba hasta la avenida del Siglo XX. Fuente visual: Biblioteca Nacional de Espaâ”śâ–’a.', 1927, 1927, 1927, 'Anos 20', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20356110011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20356110011.webp', 'https://www.flickr.com/photos/zaragozaantigua/20356110011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25071, 'Alfonso Guerra 1986', 'Visita al Palacio Municipal de Deportes de Zaragoza del vicepresidente del gobierno espaâ”śâ–’ol entre 1982 y 1991, Alfonso Guerra. Le flanquean Antonio Gonzâ”śĂ­lez Triviâ”śâ–’o (con barba), alcalde de Zaragoza; y Santiago Marraco (puâ”śâ–’o en alto), presidente de la Diputaciâ”śâ”‚n General de Aragâ”śâ”‚n. Fuente visual: www.zaragoza.es/ciudad/actividades/ficha_Agenda?codigo=13...', 1986, 1986, 1986, 'Anos 80', 'UNIVERSIDAD', 41.63975400, -0.90414900, '0101000020E61000005DC136E2C9EEECBF1BBE8575E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15915755852.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15915755852.webp', 'https://www.flickr.com/photos/zaragozaantigua/15915755852/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21781, 'Colegio Alemâ”śĂ­n 1936', '"La fiesta de Navidad de la colonia alemana. Los niâ”śâ–’os (sic) que tomaron parte en la fiesta organizada por el Colegio y la Colonia alemanes de nuestra ciudad, el pasado mes de diciembre, para festejar la Natividad del Seâ”śâ–’or". A comienzos de los aâ”śâ–’os 20 fue abierto un "Kindergarten" en la calle Cervantes para educar a los niâ”śâ–’os y niâ”śâ–’as alemanas instaladas provisionalmente en la ciudad tras la evacuaciâ”śâ”‚n de la colonia del II Reich en el Camerâ”śâ•‘n, como consecuencia de su derrota militar en la Gran Guerra. Con el tiempo, y la permanencia de un buen nâ”śâ•‘mero de familias alemanas, la guarderâ”śÂˇa se convirtiâ”śâ”‚ en "Colegio Alemâ”śĂ­n", y junto con el "Hogar Alemâ”śĂ­n" y el consulado local, formâ”śâ”‚ parte de la destacada "Pequeâ”śâ–’a Alemania" de Zaragoza. Cuando el partido nazi fue aupado al poder por las â”śÂ®lites econâ”śâ”‚micas como forma de acabar con la democracia de la Repâ”śâ•‘blica de Weimar, Zaragoza contâ”śâ”‚ ademâ”śĂ­s con un Jefe Provincial del "Ortsgruppe" (Grupo Local) del NSDAP, y una jerarquâ”śÂˇa partidaria nazi subordinada, como refuerzo de la labor de propaganda ideolâ”śâ”‚gica a favor del nuevo râ”śÂ®gimen alemâ”śĂ­n, reciâ”śÂ®n estrenada la Segunda Repâ”śâ•‘blica en Espaâ”śâ–’a. Su sede fue establecida tambiâ”śÂ®n en los locales de la calle Cervantes. Tras el 18 de julio de 1936, su colaboraciâ”śâ”‚n con el nuevo râ”śÂ®gimen nacionalista espaâ”śâ–’ol fue total. Con la invasiâ”śâ”‚n alemana de Polonia en setiembre de 1939, y el comienzo de una nueva gran guerra, la colonia alemana en Zaragoza fue militarizada, reclutando para el ejâ”śÂ®rcito a los varones aptos para servicio castrense, y utilizando las redes sociales y econâ”śâ”‚micas alemanas de la ciudad para respaldo, cobertura y difusiâ”śâ”‚n de los intereses de guerra del III Reich, de forma especialmente acusada tras la proclamaciâ”śâ”‚n de la "Totaler Krieg" (Guerra Total) en enero de 1943. Tras la completa derrota militar alemana de 1945, se cerrâ”śâ”‚ bruscamente esta etapa de la historia de la colonia alemana en Zaragoza.', 1936, 1936, 1936, 'Anos 30', 'UNIVERSIDAD', 41.64397500, -0.88708100, '0101000020E61000002EE57CB1F762ECBF8638D6C56DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22984769261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22984769261.webp', 'https://www.flickr.com/photos/zaragozaantigua/22984769261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21848, 'Gascâ”śâ”‚n de Gotor 1934', 'Panorâ”śĂ­mica imagen del entorno donde fue ubicado el brote psicâ”śâ”‚tico-mediâ”śĂ­tico asociado al denominado &quot;duende de la hornilla&quot;, en el chaflanero edificio entre la calle Gascâ”śâ”‚n de Gotor y la nueva calle de Juan Pablo Bonet que, hacia la derecha, deberâ”śÂˇa conectar la avenida de la Repâ”śâ•‘blica y el camino de las Torres con el reciente puente de la vâ”śÂˇa Transversal y el ensanche de Miralbueno. Merodeando los alrededores, nutrida congregaciâ”śâ”‚n de gente curiosa del inane mundo de los espâ”śÂˇritus fogoneros. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63985000, -0.88714900, '0101000020E610000038BBB54C8663ECBF3D2CD49AE6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35693007164.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35693007164.webp', 'https://www.flickr.com/photos/zaragozaantigua/35693007164/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21894, 'La casa del Duende 1934', 'Imagen centrada en el chaflanero edificio entre la calle Gascâ”śâ”‚n de Gotor (hacia la izquierda) y la nueva calle de Juan Pablo Bonet que, hacia la derecha, conectarâ”śÂˇa la avenida de la Repâ”śâ•‘blica y el camino de las Torres con el reciente puente de la vâ”śÂˇa Transversal y el ensanche de Miralbueno. Aquâ”śÂˇ se desatâ”śâ”‚ a finales de 1934 un brote psicâ”śâ”‚tico-mediâ”śĂ­tico en torno al que ha pasado a la historia como "duende de la hornilla", o "duende de Zaragoza". Merodeando los despejados alrededores, nutrida congregaciâ”śâ”‚n de gente atraâ”śÂˇda por la expectaciâ”śâ”‚n creada en torno a la pretendida presencia de este fantâ”śĂ­stico y juguetâ”śâ”‚n espâ”śÂˇritu fogonero. Esta fotografâ”śÂˇa, con la leyenda "El duende de Zaragoza. La casa", y acompaâ”śâ–’ada de una fotografâ”śÂˇa que muestra el interior de la cocina o "Habitaciâ”śâ”‚n donde se escucha la voz", forma parte de una tarjeta postal circulada reglamentariamente en la â”śÂ®poca y que se subasta al alucinante precio de 250 euros.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63988500, -0.88716700, '0101000020E6100000D2E4620CAC63ECBFB9196EC0E7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49931719521.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49931719521.webp', 'https://www.flickr.com/photos/zaragozaantigua/49931719521/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21960, 'P.â”¬â•‘ del General Mola 1944', 'Las alturas del alto nâ”¬â•‘ 72 del Paseo de Mola, desde su construcciâ”śâ”‚n en 1942, siempre han sido muy propicias para capturar buenas vistas en altura, aunque esta tan poco usual parece realizada mâ”śĂ­s bien desde el nâ”¬â•‘ 2 de la calle Gascâ”śâ”‚n y Gotor, bautizada por el sensacionalismo burlesco como "Casa del Duende". Asâ”śÂˇ, enfoca hacia el antiguo "Camino del Gas", por conducir a la "Fâ”śĂ­brica de Gas", al Gasâ”śâ”‚metro, aunque su denominaciâ”śâ”‚n mâ”śĂ­s habitual es Camino de las Torres. A la izquierda, el caracterâ”śÂˇstico edificio "Casa Faci" con su fantâ”śĂ­stica torre neomudâ”śÂ®jar, otro de los no oficiales "Palomares" de la ciudad, â”śÂ®ste menos publicitado por menos câ”śÂ®ntrico. Tras su derribo en 1971, las palomas se mudarâ”śĂ­n a la plaza del Pilar, y en 1974 en su solar se construirâ”śĂ­ el actual nâ”¬â•‘ 47 del Paseo, que lleva impresa en una vidriera su castiza denominaciâ”śâ”‚n de "General Mola". Al fondo, los ladrillos y tejas que, juntos, forman el colegio de los PP. Agustinos, junto a la trinchera del ferrocarril de los directos. Antes, visual de los â”śĂ­rboles del Camino de las Alcachoferas y su acequia al aire. A la derecha del Camino de las Torres, la ancha acequia de las Adulas, tambiâ”śÂ®n conocida como "de S. Josâ”śÂ®", que recorrâ”śÂˇa al aire todo el Camino. Junto a ella aâ”śâ•‘n permanece en pie la enorme instalaciâ”śâ”‚n de la Fâ”śĂ­brica de Acumuladores Tudor "La Pilar", que apenas un par de aâ”śâ–’os despuâ”śÂ®s se mudarâ”śĂ­ a lejanâ”śÂˇsima carretera de Navarra. Toda la manzana que ocupaba la fâ”śĂ­brica comenzarâ”śĂ­ a urbanizarse con nuevos edificios de viviendas, a partir de 1958. Mâ”śĂ­s al fondo, campos de cultivos y huertos de Miraflores. Desciende como una exhalaciâ”śâ”‚n desde las terrazas de Cuâ”śÂ®llar una unidad con remolque de la serie 50 de la Lâ”śÂˇnea 3/5 (Torrero-Delicias) del tranvâ”śÂˇa de Zaragoza. Los entendidos dicen que iba pintado en amarillo. Lo que estâ”śĂ­ claro es que no hay conflicto con el carretero que se le aproxima sin pestaâ”śâ–’ear. Nadie saliâ”śâ”‚ herido. Fuente visual: Imâ”śĂ­genes Antiguas de Zaragoza.', 1944, 1944, 1944, 'Anos 40', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20251541252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20251541252.webp', 'https://www.flickr.com/photos/zaragozaantigua/20251541252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21975, 'P.â”¬â•‘ del General Mola c.1940', 'Nâ”¬â•‘ 64 del antiguo paseo de Sagasta, hotelito de Sâ”śĂ­nchez Ventura diseâ”śâ–’ado en 1927 por Josâ”śÂ® y Regino Borobio con el sello de su particular interpretaciâ”śâ”‚n regionalista del racionalismo arquitectâ”śâ”‚nico de la â”śÂ®poca. A finales de la dâ”śÂ®cada de los aâ”śâ–’os 60, esta casa, a la derecha de la imagen, serâ”śĂ­ derribada y sustituidas por un edificio residencial. A la derecha, su vecina del nâ”¬â•‘ 62 del paseo, antigua Villa Dolores, correrâ”śĂ­ igual suerte en los aâ”śâ–’os 70. Fuente visual: foto Miguel Marâ”śÂˇn Chivite, en "Regino y Josâ”śÂ® Borobio: arquitectura y fotografâ”śÂˇa. Zaragoza, 1923-1969", Iâ”śâ–’aki Bergera y Daniel Estabâ”śÂ®n, IFC, 2015.', 1940, 1940, 1940, 'Anos 40', 'UNIVERSIDAD', 41.64051100, -0.88657200, '0101000020E6100000F793313ECC5EECBF37DDB243FCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24645864255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24645864255.webp', 'https://www.flickr.com/photos/zaragozaantigua/24645864255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22032, 'P.â”¬â•‘ de Ruiseâ”śâ–’ores 1946', 'Inâ”śÂ®dita imagen del Sanatorio neuro-psiquiâ”śĂ­trico de Santa Isabel reciâ”śÂ®n inaugurado en el nâ”¬â•‘ 3 del paseo de Ruiseâ”śâ–’ores, que bajo la direcciâ”śâ”‚n del prestigioso doctor Josâ”śÂ® Marâ”śÂˇa Juliâ”śĂ­n Gil y la asistencia de las Hermanas de la Caridad de Santa Ana, tenâ”śÂˇa capacidad para 30 enfermos "nerviosos y mentales". Este "magnâ”śÂˇfico establecimiento mâ”śÂ®dico" se ubicaba en el inmueble construido a principios de la dâ”śÂ®cada para albergar el nuevo Colegio Alemâ”śĂ­n que la completa derrota militar del râ”śÂ®gimen nazi en mayo de 1945 dejâ”śâ”‚ sin ese uso, siendo "reciclado" como sanatorio un aâ”śâ–’o despuâ”śÂ®s. Al fondo y a la derecha, fachada del reciente inmueble del nâ”¬â•‘ 9-11 del paseo de Cuâ”śÂ®llar.', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63778500, -0.88653400, '0101000020E61000009758198D7C5EECBF8F705AF0A2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51793078755.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51793078755.webp', 'https://www.flickr.com/photos/zaragozaantigua/51793078755/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22194, 'Parroquia Perpetuo Socorro aâ”śâ–’os 50', 'Foto: Miguel Marâ”śÂˇn Chivite. Convento y parroquia de Nuestra Seâ”śâ–’ora del Perpetuo Socorro, de la congregaciâ”śâ”‚n del Santâ”śÂˇsimo Redentor. Levantado en 1950 segâ”śâ•‘n proyecto de Joaquâ”śÂˇn Maggioni de 1947. Frente a ella, la trinchera del ferrocarril desde la estaciâ”śâ”‚n Campo Sepulcro, cubierta a partir de 1960 para transformarse en avenida de Goya. Fuente: www.facebook.com/photo.php?fbid=10208803741877479&set...', 1950, 1950, 1959, 'Anos 50', 'UNIVERSIDAD', 41.64258400, -0.88730900, '0101000020E61000006F490ED8D564ECBF6877483140D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32807467093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32807467093.webp', 'https://www.flickr.com/photos/zaragozaantigua/32807467093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25083, 'Calle Domingo Miral 1964', 'Imagen capturada durante la ceremonia de colocaciâ”śâ”‚n de la primera piedra de la Residencia de Estudiantes en el campus universitario de la plaza de San Francisco. En primer plano, el joven jefe nacional del oficial Sindicato Espaâ”śâ–’ol Universitario, Rodolfo Martâ”śÂˇn Villa. Aâ”śâ–’os despuâ”śÂ®s, serâ”śÂˇa ministro en los gobiernos de Carlos Arias Navarro y Adolfo Suâ”śĂ­rez, y vicepresidente en el de Leopoldo Calvo Sotelo. Posteriormente, continuâ”śâ”‚ centrado en la tarea de hacer polâ”śÂˇtica de alto nivel, por la vâ”śÂˇa empresarial, a travâ”śÂ®s de diversas corporaciones multinacionales. Al fondo de la imagen, la calle Domingo Miral, y el cuartel de Palafox. Dos sacerdotes garantizan la adecuada ortodoxia confesional del ceremonial. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.64056900, -0.90031900, '0101000020E610000023F59ECA69CFECBF6CEA3C2AFED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30642722294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30642722294.webp', 'https://www.flickr.com/photos/zaragozaantigua/30642722294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22218, 'Paseo de Cuâ”śÂ®llar c.1951', 'Imagen capturada desde la altura del antiguo inmueble del nâ”¬â•‘ 35 del paseo de Cuâ”śÂ®llar, luego derribado y sustituido por un moderno bloque de viviendas, con una vista centrada en el Sacrario Militare Italiano, o "Torre Funeraria, Iglesia y Convento de Capuchinos en Zaragoza para Panteâ”śâ”‚n de italianos muertos en la cruzada espaâ”śâ–’ola y servicios de culto". La demediada torre (30 metros de altura de los previstos 60) e iglesia en el centro; el convento, a la derecha. A la izquierda e inmediato, tejado a doble altura del inmueble del 55-59 del paseo, donde estaban ubicadas las Escuelas de La Milagrosa, esquineras con la antigua cabaâ”śâ–’era, moderna Vâ”śÂˇa de San Fernando. Sobre el paseo maniobra una composiciâ”śâ”‚n tranviaria de la lâ”śÂˇnea 5. Torrero-Delicias (con unidad motor de la serie 60), posiblemente realizando un servicio corto entre la plaza de Aragâ”śâ”‚n y la Playa de Torrero, de regreso hacia su norteâ”śâ–’a terminal. Al fondo y a la izquierda, tras el puente de Amâ”śÂ®rica destaca el veterano inmueble del nâ”¬â•‘ 1 de la Vâ”śÂˇa de Pignatelli, esquinero con el arranque de la avenida de Amâ”śÂ®rica, por encima de las parcelas que caracterizaban la barriada de Venecia. En primer tâ”śÂ®rmino, un carro tirado por caballerâ”śÂˇa asciende hacia Torrero, calmo y sin agobios circulatorios.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.63543500, -0.88482800, '0101000020E61000000AB952CF8250ECBFECDD1FEF55D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48279199596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48279199596.webp', 'https://www.flickr.com/photos/zaragozaantigua/48279199596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
